 {"id":"bd-2d4","title":"Implement dynamic enable/disable per-session visibility","description":"# Implement Dynamic Enable/Disable Per-Session Visibility

## Background
Python FastMCP supports dynamically enabling/disabling tools, resources, and prompts on a per-session basis. This allows servers to adapt available functionality based on user permissions, feature flags, or runtime conditions.

## Requirements

### Session-Level Control
```rust
impl McpContext {
    /// Disable a tool for this session only
    pub fn disable_tool(&self, name: &str) -> Result<(), McpError>

    /// Re-enable a previously disabled tool
    pub fn enable_tool(&self, name: &str) -> Result<(), McpError>

    /// Check if a tool is enabled for this session
    pub fn is_tool_enabled(&self, name: &str) -> bool

    // Same for resources and prompts
    pub fn disable_resource(&self, uri: &str) -> Result<(), McpError>
    pub fn enable_resource(&self, uri: &str) -> Result<(), McpError>
    pub fn disable_prompt(&self, name: &str) -> Result<(), McpError>
    pub fn enable_prompt(&self, name: &str) -> Result<(), McpError>
}
```

### Use Cases
```rust
#[tool]
async fn authenticate(ctx: &McpContext, token: String) -> Result<String, ToolError> {
    let user = validate_token(&token).await?;

    // Enable tools based on user's permissions
    if user.is_admin {
        ctx.enable_tool("admin_panel")?;
        ctx.enable_tool("user_management")?;
    }

    // Disable the auth tool after successful auth
    ctx.disable_tool("authenticate")?;

    Ok(format!("Welcome, {}", user.name))
}
```

### Session State
```rust
struct SessionState {
    disabled_tools: HashSet<String>,
    disabled_resources: HashSet<String>,
    disabled_prompts: HashSet<String>,
}

impl Session {
    fn is_component_enabled(&self, component_type: ComponentType, name: &str) -> bool {
        match component_type {
            ComponentType::Tool => !self.state.disabled_tools.contains(name),
            ComponentType::Resource => !self.state.disabled_resources.contains(name),
            ComponentType::Prompt => !self.state.disabled_prompts.contains(name),
        }
    }
}
```

### List Filtering
```rust
impl Server {
    async fn list_tools(&self, session: &Session) -> ListToolsResult {
        let tools = self.router.list_tools()
            .into_iter()
            .filter(|t| session.is_component_enabled(ComponentType::Tool, &t.name))
            .collect();

        ListToolsResult { tools }
    }
}
```

## Files to Modify
- crates/fastmcp-core/src/context.rs
- crates/fastmcp-server/src/session.rs
- crates/fastmcp-server/src/server.rs
- crates/fastmcp-server/src/router.rs

## User Experience Considerations
- Disabled components don't appear in list responses
- Calling disabled component returns clear error
- State changes are session-local (don't affect other sessions)
- Optional: emit notification when components change

---

## Comprehensive Testing Requirements

### Unit Tests

```rust
#[cfg(test)]
mod visibility_tests {
    use super::*;

    #[test]
    fn test_disable_tool() {
        let mut session = Session::new();
        assert!(session.is_component_enabled(ComponentType::Tool, "admin"));

        session.disable_tool("admin").unwrap();
        assert!(!session.is_component_enabled(ComponentType::Tool, "admin"));
    }

    #[test]
    fn test_enable_disabled_tool() {
        let mut session = Session::new();
        session.disable_tool("tool").unwrap();
        session.enable_tool("tool").unwrap();
        assert!(session.is_component_enabled(ComponentType::Tool, "tool"));
    }

    #[test]
    fn test_disable_nonexistent_tool_error() {
        let session = Session::new();
        // Should return error for unknown tool
        assert!(session.disable_tool("nonexistent").is_err());
    }

    #[test]
    fn test_session_isolation() {
        let mut session1 = Session::new();
        let session2 = Session::new();

        session1.disable_tool("shared_tool").unwrap();

        assert!(!session1.is_component_enabled(ComponentType::Tool, "shared_tool"));
        assert!(session2.is_component_enabled(ComponentType::Tool, "shared_tool"));
    }
}
```

### Integration Tests

```rust
#[tokio::test]
async fn test_disabled_tool_not_in_list() {
    let server = create_test_server();
    let session = server.create_session().await;

    // Initially visible
    let tools = server.list_tools(&session).await.unwrap();
    assert!(tools.tools.iter().any(|t| t.name == "admin"));

    // Disable
    session.context().disable_tool("admin").unwrap();

    // No longer visible
    let tools = server.list_tools(&session).await.unwrap();
    assert!(!tools.tools.iter().any(|t| t.name == "admin"));
}

#[tokio::test]
async fn test_calling_disabled_tool_errors() {
    let server = create_test_server();
    let session = server.create_session().await;

    session.context().disable_tool("query").unwrap();

    let result = server.call_tool(&session, "query", json!({})).await;
    assert!(result.is_err());
    assert!(result.unwrap_err().message.contains("disabled"));
}

#[tokio::test]
async fn test_dynamic_enable_after_auth() {
    #[tool]
    async fn login(ctx: &McpContext) -> Result<String, ToolError> {
        ctx.enable_tool("protected_tool")?;
        Ok("logged in".into())
    }

    let server = ServerBuilder::new("test", "1.0")
        .tool(login)
        .tool_disabled_by_default(protected_tool)
        .build();

    let session = server.create_session().await;

    // Protected not available initially
    let tools = server.list_tools(&session).await.unwrap();
    assert!(!tools.tools.iter().any(|t| t.name == "protected_tool"));

    // Login enables it
    server.call_tool(&session, "login", json!({})).await.unwrap();

    let tools = server.list_tools(&session).await.unwrap();
    assert!(tools.tools.iter().any(|t| t.name == "protected_tool"));
}
```

